import android.app.Activity
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import kotlinx.android.synthetic.main.activity_login.*

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        val authManager = ContextCompat.getSystemService(this, AuthManager::class.java) as AuthManager
        if (authManager.isAuthenticated()) {
            gotoHomeScreen()
            return
        }

        biometricPrompt = BiometricPrompt(this, ContextCompat.getMainExecutor(this),
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    gotoPasswordScreen()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(resources.getString(R.string.authenticate))
            .setSubtitle(resources.getString(R.string.verify_your_identity))
            .setDescription(resources.getString(R.string.use_fingerprint_to_login))
            .setNegativeButtonText(resources.getString(R.string.cancel))
            .build()

        btnBiometric.setOnClickListener {
            biometricPrompt.authenticate(promptInfo)
        }
    }

    private fun gotoHomeScreen() {
        val intent = Intent(this, HomeActivity::class.java)
        startActivity(intent)
        finish()
    }

    private fun gotoPasswordScreen() {
        val intent = Intent(this, PasswordActivity::class.java)
        startActivity(intent)
        finish()
    }
}

class AuthManager : SharedPreferences {

    companion object {
        const val KEY_AUTHENTICATED = "authenticated"
    }

    override fun getString(key: String, defaultValue: String): String {
        return getSharedPreferences("prefs", MODE_PRIVATE).getString(key, defaultValue)
    }

    override fun edit(): Editor {
        return getSharedPreferences("prefs", MODE_PRIVATE).edit()
    }

    fun isAuthenticated(): Boolean {
        val prefs = getSharedPreferences("prefs", MODE_PRIVATE)
        return prefs.getBoolean(KEY_AUTHENTICATED, false)
    }
}